import React, {
    Fragment,
    type Ref,
    type RefObject,
    useImperativeHandle,
    useRef,
} from "react";
import { Toast } from "primereact/toast";
import { Flex } from "../../_compat";
import { ProgressSpinner } from "primereact/progressspinner";
import type {IKitsToastRef, IToastFunction, ToastPosition} from "@lmb-it/kitsconcerto-types";
import {useKitsTheme} from "../../contexts/Theme";

const KitsToast = ({ ref }: { ref?: Ref<IKitsToastRef> }) => {
    const topLeftRef = useRef<Toast>(null);
    const topRightRef = useRef<Toast>(null);
    const bottomLeftRef = useRef<Toast>(null);
    const bottomRightRef = useRef<Toast>(null);
    const topCenterRef = useRef<Toast>(null);
    const bottomCenterRef = useRef<Toast>(null);

    const getToastRef = (position: ToastPosition): RefObject<Toast | null> => {
        switch (position) {
            case "top-left":
                return topLeftRef;
            case "top-right":
                return topRightRef;
            case "bottom-left":
                return bottomLeftRef;
            case "bottom-right":
                return bottomRightRef;
            case "top-center":
                return topCenterRef;
            case "bottom-center":
            default:
                return bottomCenterRef;
        }
    };

    const toast: IToastFunction = (
        severity,
        summary,
        body = "",
        position = "bottom-center",
        isUpdate = false
    ) => {
        const toastRef = getToastRef(position);
        if (!toastRef.current) return;

        const action = isUpdate ? toastRef.current.replace : toastRef.current.show;

        if (severity === "loading") {
            action({
                severity: "info",
                summary,
                detail: body,
                sticky: true,
                content: (
                    <Flex flex={1} flexDirection="row" alignItems="center" gap={10}>
                        <ProgressSpinner
                            style={{ width: 25, height: 25 }}
                            strokeWidth="8"
                            fill="var(--surface-ground)"
                            animationDuration=".5s"
                        />
                        <div className="font-medium text-lg text-900">{summary}</div>
                    </Flex>
                ),
            });
            return;
        }

        if (severity === "brand") {
            action({
                severity: "info",
                summary,
                detail: body,
                life: 3000,
                className: "kits-toast-brand",
            });
            return;
        }

        action({
            severity,
            summary,
            detail: body,
            life: 3000,
        });
    };

    const dismiss = (position?: ToastPosition) => {
        const toastRef = getToastRef(position ?? "bottom-center");
        toastRef.current?.clear();
    };

    const dismissAll = () => {
        topLeftRef.current?.clear();
        topRightRef.current?.clear();
        bottomLeftRef.current?.clear();
        bottomRightRef.current?.clear();
        topCenterRef.current?.clear();
        bottomCenterRef.current?.clear();
    };

    useImperativeHandle(ref, () => ({ toast, dismiss, dismissAll }));

    return (
        <Fragment>
            <Toast ref={topLeftRef} position="top-left" />
            <Toast ref={topRightRef} position="top-right" />
            <Toast ref={bottomLeftRef} position="bottom-left" />
            <Toast ref={bottomRightRef} position="bottom-right" />
            <Toast ref={topCenterRef} position="top-center" />
            <Toast ref={bottomCenterRef} position="bottom-center" />
        </Fragment>
    );
};

export default KitsToast;
